from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
import redis.asyncio as redis
import asyncio
from typing import Optional

app = FastAPI()
security = HTTPBearer()

# Redis client
redis_client = redis.from_url("redis://localhost:6379", decode_responses=True)

async def validate_token(credentials: HTTPAuthorizationCredentials = Depends(security)) -> str:
    """Dependency to validate OAuth 2.0 bearer token against Redis cache"""
    if credentials.scheme != "Bearer":
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid authentication scheme",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token = credentials.credentials
    
    # Check if token exists in Redis cache
    try:
        exists = await redis_client.exists(token)
        if not exists:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": "Bearer"},
            )
        return token
    except Exception:
        raise HTTPException(
            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Token validation service unavailable",
        )

@app.get("/protected")
async def protected_endpoint(token: str = Depends(validate_token)):
    """Protected endpoint that requires valid OAuth 2.0 bearer token"""
    return {"message": "Access granted", "token": token}

@app.get("/health")
async def health_check():
    """Health check endpoint"""
    try:
        await redis_client.ping()
        return {"status": "healthy", "redis": "connected"}
    except Exception:
        return {"status": "unhealthy", "redis": "disconnected"}